// ============================================================
// CV12 — CODAGE MULTIPLE (N passes codage double aveugle)
// N × { CONV-E codage indépendant + CONV-B codage indépendant }
// Double aveugle préservé : B ne voit jamais les scores de E
// ============================================================
"use strict";
const https  = require("https");
const fs     = require("fs");
const { execSync } = require("child_process");
const data   = $input.item.json;

const API_KEY  = $env.ANTHROPIC_API_KEY;
const MODEL    = $env.MEPA_IA_MODEL || "claude-sonnet-4-20250514";
const SCRIPTS  = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";
const N_PASSES = 3; // pilote CV12

const wp_id    = data.wp_id;
const ctx      = data.llm_context || {};
const cas      = ctx.cas || data.cas || wp_id;
const periode  = ctx.periode || data.periode || "";
const cluster  = ctx.cluster || data.cluster || "";
const sa       = ctx.sa ?? data.sa ?? 4;

// ── Helpers ─────────────────────────────────────────────────────────────────
const sleep = ms => new Promise(r => setTimeout(r, ms));

function httpsPost(body, beta) {
  return new Promise((res, rej) => {
    const payload = JSON.stringify(body);
    const req = https.request({
      hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": API_KEY,
        "anthropic-version": "2023-06-01",
        "anthropic-beta": "prompt-caching-2024-07-31",
        "Content-Length": Buffer.byteLength(payload)
      }
    }, r => {
      let d = ""; r.on("data", c => d += c);
      r.on("end", () => {
        if (r.statusCode !== 200) { rej(new Error(`HTTP ${r.statusCode}: ${d.slice(0,200)}`)); return; }
        try { res(JSON.parse(d)); } catch(e) { rej(new Error(`Parse: ${e.message}`)); }
      });
    });
    req.setTimeout(120000, () => { req.destroy(); rej(new Error("Timeout 120s")); });
    req.on("error", rej);
    req.write(payload); req.end();
  });
}

function extractText(response) {
  return response?.content?.find(b => b.type === "text")?.text || "{}";
}

function parseJSON(text) {
  return JSON.parse(text.replace(/```json|```/g, "").trim());
}

// ── Prompts ─────────────────────────────────────────────────────────────────
// Lire les instructions depuis le disque
const convE_instructions = fs.readFileSync(`${SCRIPTS}/CONV-E.md`, "utf8");
const convB_instructions = fs.readFileSync(`${SCRIPTS}/CONV-B.md`, "utf8");

// Sources documentaires (depuis llm_context)
const sources = ctx.sources_documentaires || ctx.sources || "";
const fiche_variables = ctx.variables || data.variables || {};
const fiche_commandes = ctx.commandes || data.commandes || {};

const SYSTEM_E = `${convE_instructions}

Tu es CONV-E, l'Historien-Codeur du projet MEPA V6.2.
Tu codes indépendamment les 9 variables critiques du WP.
Réponds UNIQUEMENT en JSON valide, sans markdown.`;

const USER_E = `WP : ${wp_id} | Cas : ${cas} | Période : ${periode} | Cluster : ${cluster}

Sources documentaires disponibles :
${sources}

Variables à coder (format attendu en retour) :
{
  "variables_codees": {
    "E_split": {"valeur": 0.0, "justification": "..."},
    "gamma":   {"valeur": 0.0, "justification": "..."},
    "A_d_eff": {"valeur": 0.0, "justification": "..."},
    "A_r_c":   {"valeur": 0.0, "justification": "..."},
    "A_r_ne":  {"valeur": 0.0, "justification": "..."},
    "Cs":      {"valeur": 0.0, "justification": "..."},
    "L_t":     {"valeur": 0.0, "justification": "..."},
    "EROI":    {"valeur": 0.0, "justification": "..."},
    "Sa":      {"valeur": ${sa}, "justification": "..."}
  },
  "date_codage": "${new Date().toISOString().split("T")[0]}"
}`;

const SYSTEM_B = `${convB_instructions}

Tu es CONV-B, l'Auditeur Scientifique MEPA V6.2.
Tu codes indépendamment les 9 variables critiques du WP.
Tu ne vois PAS les scores de CONV-E. Double aveugle strict.
Réponds UNIQUEMENT en JSON valide, sans markdown.`;

const USER_B = `WP: ${wp_id} | Cas: ${cas} | Periode: ${periode} | Cluster: ${cluster}

Sources pour codage independant:
${sources}

{
  "date_codage": "${new Date().toISOString().split("T")[0]}",
  "variables_conv_b": {
    "E_split": {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "gamma":   {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_d_eff": {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_r_c":   {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "A_r_ne":  {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "Cs":      {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "L_t":     {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "EROI":    {"valeur": 0.0, "indicateur": "...", "source_utilisee": "...", "justification": "..."},
    "Sa":      {"valeur": 0,   "source_utilisee": "...", "justification": "..."}
  }
}`;

// ── N passes de codage double aveugle ────────────────────────────────────────
const pairs = [];
const VARS_CONTINUES = ["E_split","gamma","A_d_eff","A_r_c","A_r_ne","Cs","L_t","EROI"];

for (let pass = 1; pass <= N_PASSES; pass++) {
  // CONV-E code indépendamment
  const resp_e = await httpsPost({
    model: MODEL, max_tokens: 3000,
    system: [{ type: "text", text: SYSTEM_E, cache_control: { type: "ephemeral" } }],
    messages: [{ role: "user", content: USER_E }]
  });
  const e_result = parseJSON(extractText(resp_e));
  const e_vars = e_result.variables_codees || {};

  await sleep(2000); // petit délai entre appels

  // CONV-B code indépendamment (ne voit pas les scores E)
  const resp_b = await httpsPost({
    model: MODEL, max_tokens: 2000,
    system: [{ type: "text", text: SYSTEM_B, cache_control: { type: "ephemeral" } }],
    messages: [{ role: "user", content: USER_B }]
  });
  const b_result = parseJSON(extractText(resp_b));
  const b_vars_raw = b_result.variables_conv_b || {};
  const b_vars = Object.fromEntries(
    Object.entries(b_vars_raw).map(([k, v]) => [k, { valeur: typeof v === "object" ? v.valeur : v }])
  );

  // Écrire les fiches pour kappa_calculator
  const fiche_e = {
    wp_id, codeur: "CONV-E", pass,
    date_codage: new Date().toISOString(),
    variables: Object.fromEntries(
      Object.entries(e_vars).map(([k, v]) => [k, { valeur: typeof v === "object" ? v.valeur : v }])
    ),
    sa: e_vars.Sa?.valeur ?? sa
  };
  const fiche_b = {
    wp_id, codeur: "CONV-B", pass,
    date_codage: new Date().toISOString(),
    variables: b_vars,
    sa: b_vars_raw.Sa?.valeur ?? sa
  };

  const fe_path = `/tmp/${wp_id}_cv12_e_${pass}.json`;
  const fb_path = `/tmp/${wp_id}_cv12_b_${pass}.json`;
  fs.writeFileSync(fe_path, JSON.stringify(fiche_e, null, 2));
  fs.writeFileSync(fb_path, JSON.stringify(fiche_b, null, 2));

  // CCI pour cette paire
  const cci_path = `/tmp/${wp_id}_cv12_cci_${pass}.json`;
  let cci_pass = null, cci_error = null;
  try {
    execSync(`/usr/bin/python3 ${SCRIPTS}/mepa_kappa_calculator.py ${fe_path} ${fb_path} ${cci_path}`,
      { encoding: "utf8", maxBuffer: 5*1024*1024 });
    cci_pass = JSON.parse(fs.readFileSync(cci_path, "utf8"));
  } catch(e) { cci_error = e.message; }

  pairs.push({
    pass,
    e_vars: fiche_e.variables,
    b_vars: fiche_b.variables,
    cci: cci_pass?.cci ?? null,
    verdict: cci_pass?.verdict ?? "NON_CALCULE",
    cci_error,
    fe_path, fb_path
  });
}

return {
  json: {
    ...data,
    cv12_pairs: pairs,
    cv12_n_passes: N_PASSES,
    status: "CV12_CODAGE_DONE"
  }
};

// ============================================================
// CV12 — CONSOLIDATION
// CCI agrégé sur N paires + codage consolidé (médiane)
// Produit la fiche consolidée qui alimente le runner
// ============================================================
"use strict";
const data   = $input.item.json;
const pairs  = data.cv12_pairs || [];
const wp_id  = data.wp_id;

const VARS_CONTINUES = ["E_split","gamma","A_d_eff","A_r_c","A_r_ne","Cs","L_t","EROI"];
const VARS_ALL       = [...VARS_CONTINUES, "Sa"];

// ── CCI agrégé ───────────────────────────────────────────────────────────────
const cci_values = pairs.filter(p => p.cci !== null).map(p => p.cci);
const cci_agrege = cci_values.length > 0
  ? parseFloat((cci_values.reduce((a,b) => a+b, 0) / cci_values.length).toFixed(4))
  : null;

// Verdict sur CCI agrégé (seuils V6.2)
const verdict_cci_agrege = cci_agrege === null ? "NON_CALCULE"
  : cci_agrege >= 0.70 ? "CERTIFIE"
  : cci_agrege >= 0.50 ? "REVISION"
  : "REJET";

// ── Médiane par variable ─────────────────────────────────────────────────────
// Agrège TOUTES les valeurs (N scores E + N scores B) par variable
function median(arr) {
  const sorted = [...arr].filter(v => v !== null && v !== undefined && !isNaN(v)).sort((a,b)=>a-b);
  if (!sorted.length) return null;
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid-1] + sorted[mid]) / 2;
}

const codage_consolide = {};
for (const varName of VARS_ALL) {
  const all_values = [];
  for (const pair of pairs) {
    const e_val = pair.e_vars?.[varName]?.valeur;
    const b_val = pair.b_vars?.[varName]?.valeur;
    if (e_val !== undefined && e_val !== null) all_values.push(Number(e_val));
    if (b_val !== undefined && b_val !== null) all_values.push(Number(b_val));
  }
  const med = median(all_values);
  // Sa est catégorielle — arrondir à l'entier le plus proche dans {2,4,6,7}
  if (varName === "Sa" && med !== null) {
    const sa_valides = [2, 4, 6, 7];
    const sa_arrondi = sa_valides.reduce((prev, curr) =>
      Math.abs(curr - med) < Math.abs(prev - med) ? curr : prev
    );
    codage_consolide[varName] = { valeur: sa_arrondi, source: "cv12_mediane", n_valeurs: all_values.length };
  } else {
    codage_consolide[varName] = { valeur: med, source: "cv12_mediane", n_valeurs: all_values.length };
  }
}

// ── Injecter le codage consolidé dans la fiche ──────────────────────────────
// Format attendu par Nœud 3 et le runner : même structure que la sortie CONV-E
const fiche_consolidee = {
  ...data,
  // Remplacer les variables par le codage consolidé
  variables: {
    ...(data.variables || {}),
    ...Object.fromEntries(
      Object.entries(codage_consolide).map(([k, v]) => [
        k, { ...(data.variables?.[k] || {}), valeur: v.valeur, source_cv12: v.source }
      ])
    )
  },
  codeur: "CV12_CONSOLIDE",
  cv12_consolidation: {
    n_passes:         pairs.length,
    cci_par_passe:    pairs.map(p => ({ pass: p.pass, cci: p.cci, verdict: p.verdict })),
    cci_agrege:       cci_agrege,
    verdict_agrege:   verdict_cci_agrege,
    codage_consolide: codage_consolide,
    methode:          "mediane_2N_valeurs"
  },
  // Champs attendus en aval par Nœud 3 → runner
  cci_global:    cci_agrege,
  verdict_cci:   verdict_cci_agrege,
  cci_result:    { cci: cci_agrege, verdict: verdict_cci_agrege },
  scores_resolus: Object.fromEntries(
    Object.entries(codage_consolide).map(([k, v]) => [k, v.valeur])
  ),
  status: "CV12_CONSOLIDE"
};

// Log de consolidation
const log_lines = [
  `[CV12 CONSOLIDATION] ${wp_id}`,
  `  N passes : ${pairs.length}`,
  `  CCI par passe : ${pairs.map(p => `P${p.pass}=${p.cci?.toFixed(3)??"null"}`).join(", ")}`,
  `  CCI agrégé : ${cci_agrege?.toFixed(3) ?? "null"} → ${verdict_cci_agrege}`,
  `  Codage consolidé (médiane) :`,
  ...Object.entries(codage_consolide).map(([k,v]) => `    ${k}: ${v.valeur} (n=${v.n_valeurs})`)
];
console.log(log_lines.join("\n"));

return { json: fiche_consolidee };

// Nœud B — Decode Binary → JSON (No-FS)
// Remplace "Extract From File" qui encapsule sous une clé "data" parasite
// Retourne le JSON de la fiche directement à la racine pour le Nœud 2

const binaryData = $input.item.binary.data;
const raw = Buffer.from(binaryData.data, 'base64').toString('utf-8');
return { json: JSON.parse(raw) };

// NOEUD 8d -- Injection Valeurs Resolues (post-CCI) dans runner_config
// Protocole : runner tourne sur valeurs FINALES apres resolution inter-codeurs
"use strict";
const data = $input.item.json;

const scores_resolus = data.scores_resolus || {};
const fiche_input    = data.llm_context?.mepa_full_vars || {};

// Construire les commandes avec les valeurs resolues
// Priorite : scores_resolus (post-CCI) > valeur fiche CONV-E
const cmd_base = { ...(data.llm_context?.cmd_brut || {}) };

// Mapper variables MEPA -> commandes runner
const VAR_TO_CMD = {
  'gamma':   'gamma',   // γ organisationnel → cmd.gamma
  'A_r_c':   'Rc',      // répression classique → cmd.Rc
  'A_r_ne':  'Rn',      // répression numérique → cmd.Rn
  'E_split':  'E',      // fracture élite → cmd.E [CORRECTIF A3]
  'Cs':      'Mob',     // crédibilité/mobilisation → cmd.Mob [CORRECTIF A3]
  // A_d_eff → cmd.R : CONV-E code R directement dans commandes_mises_a_jour
  // L_t → conditions_initiales.L0 : géré séparément ci-dessous
};

// Correction L0 depuis scores_resolus si L_t résolu post-CCI [CORRECTIF A3]
if (scores_resolus['L_t'] !== undefined) {
  let runner_cfg_l0 = {};
  try { runner_cfg_l0 = JSON.parse(data.runner_config_json || "{}"); } catch(e) {}
  if (!runner_cfg_l0.y0) runner_cfg_l0.y0 = [1.0, 0.3, 0.1, 4.0];
  if (Array.isArray(runner_cfg_l0.y0)) {
    runner_cfg_l0.y0[1] = scores_resolus['L_t']; // index 1 = L0
  } else if (typeof runner_cfg_l0.y0 === 'object') {
    runner_cfg_l0.y0['L'] = scores_resolus['L_t'];
    runner_cfg_l0.y0['L0'] = scores_resolus['L_t'];
  }
}

for (const [var_name, cmd_key] of Object.entries(VAR_TO_CMD)) {
  if (scores_resolus[var_name] !== undefined) {
    cmd_base[cmd_key] = scores_resolus[var_name];
  }
}

// Mettre a jour le runner_config_json avec les valeurs resolues
let runner_config = {};
try {
  runner_config = JSON.parse(data.runner_config_json || "{}");
} catch(e) {}

// Appliquer les corrections de commandes
if (Object.keys(cmd_base).length > 0) {
  runner_config.cmd = { ...(runner_config.cmd || {}), ...cmd_base };
}

// Sauvegarder config mise a jour
const { execSync } = require("child_process");
const fs = require("fs");
const config_path = `/tmp/${data.wp_id}_runner_config.json`;
const config_json_updated = JSON.stringify(runner_config);
fs.writeFileSync(config_path, config_json_updated);

return {
  json: {
    ...data,
    runner_config_json: config_json_updated,
    runner_config_path: config_path,
    valeurs_finales: {
      ...Object.fromEntries(
        Object.entries(fiche_input).map(([k, v]) => [
          k, scores_resolus[k] ?? v.valeur ?? v.valeur_normative_v62 ?? null
        ])
      ),
      ...scores_resolus
    },
    cci_global:   data.cci_global   ?? null,
    cci_result:   data.cci_result   ?? null,
    verdict_cci:  data.verdict_cci  ?? null,
    message: `Valeurs resolues injectees -- ${Object.keys(scores_resolus).length} variables resolues par CCI`
  }
};

// NŒUD 3 — Write Config File (No-FS via stdin)
// Architecture No-FS : transmet runner_config_json via stdin au lieu d'écriture disque directe
// Le runner Python reçoit le JSON sur stdin si aucun chemin fourni en arg

"use strict";
const data = $input.item.json;

if (data.statut_audit === "DONNEES_INSUFFISANTES") {
  return { json: { ...data, status: "NC_BLOQUANT" } };
}

const configJson = data.runner_config_json;
if (!configJson) throw new Error(`[N3] runner_config_json absent — wp_id=${data.wp_id}`);

const MEPA_SCRIPTS_DIR = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";
const wp_id       = data.wp_id;
const configPath  = data.runner_config_path || `/tmp/${wp_id}_runner_config.json`;
const resultPath  = data.result_path        || `/tmp/${wp_id}_result.json`;
const n1Path      = data.n1_path            || `/tmp/${wp_id}_n1_sensitivity.json`;

// No-FS : passer le JSON via echo | /usr/bin/python3 (heredoc shell — évite writeFileSync)
// Le runner accepte le JSON sur stdin quand l'arg est "-"
// Écriture fichier config (fs.writeFileSync — évite tout problème de quote shell)
const fs = require('fs');
fs.writeFileSync(configPath, configJson, 'utf8');
const runner_cmd = `/usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_runner_v2_gamma.py ${configPath} ${resultPath}`;
const n1_cmd     = `/usr/bin/python3 ${MEPA_SCRIPTS_DIR}/mepa_sensitivity_n1.py ${configPath} ${n1Path}`;

return {
  json: {
    status:             "CONFIG_READY",
    statut_audit:       data.statut_audit,
    wp_id,
    runner_config_json: configJson,
    runner_config_path: configPath,
    result_path:        resultPath,
    n1_path:            n1Path,
    runner_cmd,
    n1_cmd,
    llm_context:        data.llm_context    || {},
    audit_log:          data.audit_log      || {},
    nc_non_bloquantes:  data.nc_non_bloquantes || [],
    cci_global:         data.cci_global  ?? null,
    cci_result:         data.cci_result  ?? null,
    verdict_cci:        data.verdict_cci ?? null,
    scores_resolus:     data.scores_resolus || {},
    message:            `Config prête pour ${wp_id} — No-FS mode`
  }
};

// NŒUD 4 — Execute Runner (No-FS via execSync)
"use strict";
const SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";
const { execSync } = require("child_process");
const data = $input.item.json;
const configPath = data.runner_config_path || `/tmp/${data.wp_id}_runner_config.json`;
const resultPath  = data.result_path        || `/tmp/${data.wp_id}_result.json`;

// Nœud 3 a déjà écrit le fichier via fs.writeFileSync — rien à faire ici

let stdout = "", stderr = "", exitCode = 0;
try {
  stdout = execSync(
    `/usr/bin/python3 ${SCRIPTS}/mepa_runner_v2_gamma.py ${configPath} ${resultPath}`,
    { encoding: "utf8", maxBuffer: 10 * 1024 * 1024 }
  );
} catch (e) {
  stdout = e.stdout || "";
  stderr = e.stderr || "";
  exitCode = e.status || 1;
}
return {
  json: {
    ...data,
    stdout, stderr, exitCode,
    wp_id:             data.wp_id,
    result_path:       resultPath,
    n1_path:           data.n1_path,
    n1_cmd:            data.n1_cmd,
    llm_context:       data.llm_context,
    audit_log:         data.audit_log,
    nc_non_bloquantes: data.nc_non_bloquantes || []
  }
};

// NŒUD 4b — Execute Sensibilité N1 (No-FS via execSync)
"use strict";
const SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";
const { execSync } = require("child_process");
const fs = require('fs');
const data = $input.item.json;
const configPath = data.runner_config_path || `/tmp/${data.wp_id}_runner_config.json`;
const n1Path     = data.n1_path            || `/tmp/${data.wp_id}_n1_sensitivity.json`;

// Convertir y0 dict → liste [S0, L0, C0, I0] pour mepa_sensitivity_n1.py
const config = JSON.parse(data.runner_config_json);
const y0raw  = config.y0 || {};
config.y0 = [
  y0raw.S0 ?? y0raw.S ?? 1.0,
  y0raw.L0 ?? y0raw.L ?? 0.5,
  y0raw.C0 ?? y0raw.C ?? 0.1,
  y0raw.I0 ?? y0raw.I ?? 3.5
];
const configJsonFixed = JSON.stringify(config);

// Écrire la config corrigée sur disque (fs.writeFileSync — évite tout problème de quote shell)
fs.writeFileSync(configPath, configJsonFixed, 'utf8');

let stdout = "", stderr = "", exitCode = 0;
try {
  stdout = execSync(
    `/usr/bin/python3 ${SCRIPTS}/mepa_sensitivity_n1.py ${configPath} ${n1Path}`,
    { encoding: "utf8", maxBuffer: 10 * 1024 * 1024 }
  );
} catch (e) {
  stdout = e.stdout || "";
  stderr = e.stderr || "";
  exitCode = e.status || 1;
}
return {
  json: {
    ...data,
    stdout, stderr, exitCode,
    wp_id:             data.wp_id,
    n1_path:           n1Path,
    llm_context:       data.llm_context,
    audit_log:         data.audit_log,
    nc_non_bloquantes: data.nc_non_bloquantes || []
  }
};

"use strict";
const { execSync } = require("child_process");
const data    = $input.item.json;
const wp_id   = data.wp_id || "WP-INCONNU";
const resultPath = data.result_path || `/tmp/${wp_id}_result.json`;
const exitCode   = data.exitCode ?? 0;
const stderr     = data.stderr || "";
if (exitCode !== 0) {
  return {
    json: {
      status: "RUNNER_ERROR",
      wp_id, exitCode, stderr,
      result_path: resultPath,
      message: `Runner erreur — exit=${exitCode}. stderr: ${stderr.slice(0,200)}`
    }
  };
}
let resultData = null;
let parseError = null;
try {
  const raw = execSync(`cat ${resultPath}`, { encoding: "utf8" });
  resultData = JSON.parse(raw);
} catch (e) {
  parseError = e.message;
}
if (!resultData) {
  return {
    json: {
      status: "RUNNER_ERROR",
      wp_id, exitCode, stderr, parseError, resultPath,
