function filterResultData(rd) {
  if (!rd) return rd;
  const sim = rd.simulation || {};
  const filtered_sim = Object.fromEntries(
    Object.entries(sim).filter(([k]) => !['S','L','C','I'].includes(k))
  );
  return { ...rd, simulation: filtered_sim };
}

