const rapport_md = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let body = "";
    res.on("data", chunk => body += chunk);
    res.on("end", () => {
      try {
        if (res.statusCode !== 200) {
          reject(new Error(`API HTTP ${res.statusCode} : ${body.slice(0,300)}`));
          return;
        }
        const parsed = JSON.parse(body);
        const text = parsed.content?.find(b => b.type === "text")?.text || "";
        if (!text) reject(new Error(`API réponse vide — body: ${body.slice(0,200)}`));
        else resolve(text);
      } catch (e) { reject(new Error(`Parse API : ${e.message} | body: ${body.slice(0,200)}`)); }
    });
  });
