      res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
          const t = JSON.parse(body).content?.[0]?.text || "{}";
          resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
        } catch(e) { reject(e); }
      });
    });
    req.setTimeout(90000, () => { req.destroy(); reject(new Error("Timeout 90s")); });
  req.on("error", reject);
    req.write(payload); req.end();
  });
} catch(e) { audit_error = e.message; }

const verdict = audit_result?.verdict || "NON_CALCULE";
const need_revision = verdict === "REVISION_MINEURE" || verdict === "REVISION_MAJEURE";

return {
  json: {
    ...data,
    audit_conv_b: audit_result,
    verdict_conv_b: verdict,
    score_checklist: audit_result?.score_checklist || 0,
    anomalies_conv_b: audit_result?.anomalies || [],
    instructions_revision: audit_result?.instructions_revision || [],
    need_revision,
    audit_error,
    message: `CONV-B audit: ${verdict} -- ${audit_result?.score_checklist || "?"}/5`
  }
};

// NOEUD 12 -- Stress-test N2 (Combinaisons critiques)
// Protocole S3 Niveau 2 : optimiste + pessimiste sur variables sensibles N1
"use strict";
const { execSync } = require("child_process");
const fs = require("fs");

const data    = $input.item.json;
const wp_id   = data.wp_id;
const SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";

let config_base = {};
try {
  config_base = JSON.parse(fs.readFileSync(`/tmp/${wp_id}_runner_config.json`, "utf8"));
} catch(e) {
  return { json: { ...data, stress_n2: { erreur: "config non disponible" }, robustesse_n2: "NON_CALCULE" } };
}

function perturber(base, direction) {
  const cfg = JSON.parse(JSON.stringify(base));
  const d   = direction === "optimiste" ? 1 : -1;
  // Perturbations standard S3 Niveau 2
  if (cfg.cmd?.Rc  !== undefined) cfg.cmd.Rc  = Math.max(0, Math.min(1, (cfg.cmd.Rc  || 0.5) - d * 0.10));
  if (cfg.cmd?.E   !== undefined) cfg.cmd.E   = Math.max(0, Math.min(1, (cfg.cmd.E   || 0.5) - d * 0.10));
  if (cfg.cmd?.Rn  !== undefined) cfg.cmd.Rn  = Math.max(0, Math.min(1, (cfg.cmd.Rn  || 0)   - d * 0.10));
  return cfg;
}

const resultats_n2 = {};
for (const scenario of ["optimiste", "pessimiste"]) {
  const cfg      = perturber(config_base, scenario);
  const cfg_path = `/tmp/${wp_id}_n2_${scenario}.json`;
  const res_path = `/tmp/${wp_id}_n2_${scenario}_result.json`;
  // Forcer result path dans config
  cfg.result_path = res_path;
  fs.writeFileSync(cfg_path, JSON.stringify(cfg, null, 2));
  let traj_n2 = null;
  try {
    execSync(`/usr/bin/python3 ${SCRIPTS}/mepa_runner_v2_gamma.py ${cfg_path}`,
      { encoding: "utf8", timeout: 60000 });
    const raw = execSync(`cat ${res_path}`, { encoding: "utf8" });
    traj_n2 = JSON.parse(raw).simulation?.traj || "?";
  } catch(e) { traj_n2 = `ERREUR: ${e.message.slice(0,80)}`; }
  resultats_n2[scenario] = traj_n2;
}

const traj_base    = data.traj_diagn;
const bif = Object.values(resultats_n2).filter(t => t && t !== traj_base && !t.startsWith("ERREUR"));
const robustesse_n2 = bif.length === 2 ? "FRAGILE" : bif.length === 1 ? "METASTABLE" : "ROBUSTE";

return {
  json: {
    ...data,
    stress_n2: { traj_base, ...resultats_n2, robustesse_n2, bifurcations: bif },
    robustesse_n2,
    message: `N2: ${robustesse_n2} -- opt=${resultats_n2.optimiste} pes=${resultats_n2.pessimiste}`
  }
};

// NOEUD 13 -- Prediction Popper RF1/RF2/RF3
// Protocole S3 Niveau 3 + S4 : condition d'observation + horizon temporel date
"use strict";
const https = require("https");

const data   = $input.item.json;
const wp_id  = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;
const meta   = data.result_data?.meta || {};
const sim    = data.result_data?.simulation || {};

const SYSTEM = `Tu identifies la prediction falsifiable MEPA V6.2 applicable.
RF1: maintien paix sociale >15 ans malgre EROI<5 sans techno -- Fenetre 2025-2040
RF2: absence traj (a)/(d) >20 ans malgre E_split>0.7+gamma>0.5 -- Fenetre 20 ans
RF3: complexite croissante >30 ans avec EROI declinant -- Fenetre 2025-2055
Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP:${wp_id} | Cas:${meta.cas||""} | Cluster:${data.result_data?.meta?.cluster||""} | Traj:${sim.traj||""} | EROI:${data.result_data?.cmd_base?.EROI||""} | N1:${data.robustesse||""} | N2:${data.result_data?.verdict?.robustesse||""} | E_split:${data.llm_context?.mepa_full_vars?.E_split?.valeur??""} | gamma:${data.llm_context?.mepa_full_vars?.gamma?.valeur??""}
Format: {"prediction_applicable":"RF1|RF2|RF3|AUCUNE","justification":"...","condition_observation":"...","horizon_temporel":"YYYY-YYYY","seuil_refutation":"...","cas_test":"${wp_id}"}`;

let popper_result = null;
let popper_error  = null;
try {
  popper_result = await new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      model: "claude-sonnet-4-20250514", max_tokens: 600,
      system: SYSTEM, messages: [{ role: "user", content: USER }]
    });
    const req = https.request({
      hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
      headers: { "Content-Type": "application/json",
        "x-api-key": ANTHROPIC_API_KEY, "anthropic-version": "2023-06-01" }
    }, (res) => {
      let body = "";
      res.on("data", c => body += c);
      res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
          const t = JSON.parse(body).content?.[0]?.text || "{}";
          resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
        } catch(e) { reject(e); }
      });
    });
    req.setTimeout(60000, () => { req.destroy(); reject(new Error("Timeout 60s")); });
  req.on("error", reject);
    req.write(payload); req.end();
  });
} catch(e) {
  popper_error = e.message;
  popper_result = { prediction_applicable: "NON_CALCULE", erreur: popper_error };
}

return { json: { ...data, popper: popper_result, popper_error,
  message: `Popper: ${popper_result?.prediction_applicable||"?"} -- ${popper_result?.horizon_temporel||"?"}` }};

// NOEUD 14 -- Certification finale
// Protocole S7 : CCI>=0.75 + N1 robuste + concordance -> WP_CERTIFIE
"use strict";
const data = $input.item.json;
const wp_id = data.wp_id;

const cci_global     = data.cci_global    ?? null;
const robustesse_n1  = data.robustesse    || "NON_CALCULE";
const robustesse_n2  = data.robustesse_n2 || "NON_CALCULE";
const concordance    = data.concordance   ?? false;
const traj_diagn     = data.traj_diagn    || "?";
const traj_attendue  = data.result_data?.meta?.trajectoire_attendue || "?";
const verdict_conv_b = data.verdict_conv_b || "NON_CALCULE";

// Criteres de certification S7 du Guide Methodologique
const cci_ok         = cci_global !== null && cci_global >= 0.75;
const n1_ok          = ["ROBUSTE","METASTABLE"].includes(robustesse_n1);
const concordance_ok = concordance === true;
const conv_b_ok      = verdict_conv_b === "CERTIFIE"; // REVISION sans rebouclage → WP_EXPLORATOIRE

let statut = "WP_EXPLORATOIRE";
const raison = [];
if (cci_ok && n1_ok && concordance_ok && conv_b_ok) {
  statut = "WP_CERTIFIE";
} else {
  if (!cci_ok)         raison.push(`CCI=${cci_global?.toFixed(3)??"null"} < 0.75`);
  if (!n1_ok)          raison.push(`N1=${robustesse_n1}`);
  if (!concordance_ok) raison.push(`Concordance=NON (${traj_diagn} != ${traj_attendue})`);
  if (!conv_b_ok)      raison.push(`CONV-B=${verdict_conv_b}`);
}

const _certDate = new Date().toISOString().split("T")[0]; // YYYY-MM-DD

return {
  json: {
    ...data,
    date_codage_pipeline: _certDate,
    certification: {
      statut, cci_global, robustesse_n1, robustesse_n2, concordance,
      verdict_conv_b, raison_non_certifie: raison,
      popper: data.popper || null, scores_resolus: data.scores_resolus || {},
      date_certification: _certDate
    },
    statut_global: statut,
    message: `[CERTIFICATION] ${wp_id} -> ${statut} [${_certDate}]${raison.length ? " : "+raison.join(" | ") : ""}`
  }
};

// ============================================================================
// NŒUD 15 V2 — Archivage Final [Multi-passes]
// ============================================================================
// Modifications vs V1 :
//   - Tous les fichiers archivés portent le suffixe _sim_N dans leur nom
//   - Un fichier de synthèse multi-passes est généré après la dernière passe
//     (détecté via num_passe === nb_passes_total)
//   - Rétrocompatibilité : si num_passe absent, comportement V1 identique
// ============================================================================

"use strict";
const fs = require("fs");
const { execSync } = require("child_process");

const data    = $input.item.json;
const wp_id   = data.wp_id;
const BASE    = $env.MEPA_OUTPUT_DIR || "/data/mepa/outputs";
const cluster = (data.result_data?.meta?.cluster || "CX").replace(/[^A-Z0-9]/g, "");
const cert    = data.certification || {};
const sim     = data.result_data?.simulation || {};

// ── Suffixe de passe ─────────────────────────────────────────────────────────
const num_passe     = data.num_passe     ?? null;
const sim_label     = data.sim_label     ?? null;  // "sim_1", "sim_2", ...
const nb_passes     = data.nb_passes_total ?? null;
const passe_label   = data.passe_label   ?? null;
const zone          = data.zone_stratification ?? "LOI PHYSIQUE";

// Préfixe fichier : WP-F1-1_sim_1 ou WP-F1-1 (V1)
const file_prefix = sim_label ? `${wp_id}_${sim_label}` : wp_id;

// ── Répertoires ──────────────────────────────────────────────────────────────
const dirs = {
  results:      `${BASE}/cluster_${cluster}/results`,
  rapports:     `${BASE}/cluster_${cluster}/rapports`,
  passeports:   `${BASE}/passeports`,
  sensitivity:  `${BASE}/sensitivity`,
  certification:`${BASE}/certification`,
};
execSync(`mkdir -p ${Object.values(dirs).join(" ")}`);

const w = (path, content) => { fs.writeFileSync(path, content, "utf8"); return path; };
const archived = {};

// ── Archivage des fichiers de cette passe ────────────────────────────────────
if (data.result_data)
  archived.result    = w(`${dirs.results}/${file_prefix}_result.json`,
                          JSON.stringify(data.result_data, null, 2));

if (data.rapport_n1)
  archived.rapport_n1 = w(`${dirs.sensitivity}/${file_prefix}_n1.json`,
                           JSON.stringify(data.rapport_n1, null, 2));

if (data.stress_n2)
  archived.stress_n2  = w(`${dirs.sensitivity}/${file_prefix}_n2.json`,
                           JSON.stringify(data.stress_n2, null, 2));

if (data.rapport_md)
  archived.rapport_md = w(`${dirs.rapports}/${file_prefix}_rapport.md`,
                           data.rapport_md);

if (data.cci_result)
  archived.cci        = w(`${dirs.certification}/${file_prefix}_cci.json`,
                           JSON.stringify(data.cci_result, null, 2));

if (data.conv_b_data)
  archived.conv_b     = w(`${dirs.certification}/${file_prefix}_conv_b.json`,
                           JSON.stringify(data.conv_b_data, null, 2));

if (data.audit_conv_b)
  archived.audit_b    = w(`${dirs.certification}/${file_prefix}_audit_b.json`,
                           JSON.stringify(data.audit_conv_b, null, 2));

if (data.popper)
  archived.popper     = w(`${dirs.certification}/${file_prefix}_popper.json`,
                           JSON.stringify(data.popper, null, 2));

// ── Passeport de passe ───────────────────────────────────────────────────────
const passeport_passe = {
  ...(data.passeport || {}),
  num_passe,
  sim_label,
  passe_label,
  zone_stratification: zone,
  certification_v2: {
    statut:         cert.statut,
    cci_global:     cert.cci_global,
    kappa_sa:       data.cci_result?.kappa_sa ?? null,
    robustesse_n1:  cert.robustesse_n1,
    robustesse_n2:  cert.robustesse_n2,
    concordance:    cert.concordance,
    scores_resolus: cert.scores_resolus,
    verdict_conv_b: cert.verdict_conv_b,
    popper:         cert.popper,
    raison_non_certifie: cert.raison_non_certifie,
    generated_at:   new Date().toISOString(),
  }
};
archived.passeport = w(
  `${dirs.passeports}/${file_prefix}_passeport.json`,
  JSON.stringify(passeport_passe, null, 2)
);

// ── Passeport compact CONV-D ─────────────────────────────────────────────────
const popper_rf1 = data.popper?.prediction_applicable === "RF1"
  ? data.popper?.condition_observation : null;
const popper_rf2 = data.popper?.prediction_applicable === "RF2"
  ? data.popper?.condition_observation : null;

const passeport_compact = {
  wp_id,
  sim_label,
  num_passe,
  passe_label,
  zone,
  cluster,
  sa:            data.result_data?.meta?.sa ?? null,
  traj_attendue: data.result_data?.meta?.trajectoire_attendue || "?",
  traj_diagn:    sim.traj || "?",
  concordant:    cert.concordance ?? false,
  robustesse:    cert.robustesse_n1 || "?",
  t_b:           sim.t_bascule ?? null,
  dC_rel:        sim.dC_rel ?? null,
  dI_rel:        sim.dI_rel ?? null,
  CCI:           cert.cci_global ?? null,
  RF1:           popper_rf1,
  RF2:           popper_rf2,
  p6_final:      data.result_data?.params?.p6 ?? null,
  statut_cert:   cert.statut || "WP_EXPLORATOIRE",
  alertes:       data.anomalies_conv_b || [],
};
archived.passeport_compact = w(
  `${dirs.certification}/${file_prefix}_passeport_compact.json`,
  JSON.stringify(passeport_compact)
);

// ── Synthèse multi-passes (générée sur la DERNIÈRE passe uniquement) ─────────
let synthese_passes = null;
// ── Compteur atomique de passes terminées ────────────────────────────────
// Chaque exécution N15 (une par passe, en parallèle) incrémente ce compteur.
// La première passe à atteindre nb_passes déclenche la consolidation N16.
// Mécanisme fichier (append atomique) pour éviter les race conditions.
const counter_path = `/tmp/${wp_id}_pass_done_counter`;
let pass_count = 0;
try {
  // Append "1\n" — chaque passe écrit une ligne
  fs.appendFileSync(counter_path, "1\n", "utf8");
  // Compter les lignes = nombre de passes terminées
  pass_count = fs.readFileSync(counter_path, "utf8").trim().split("\n").filter(Boolean).length;
} catch(e) {
  pass_count = num_passe ?? 1;
}
// Guard null : si nb_passes est null/0, ne jamais déclencher N16
const toutes_passes_terminees = (
  nb_passes !== null && nb_passes > 0 && pass_count >= nb_passes
);

if (toutes_passes_terminees && num_passe !== null && nb_passes !== null) {

  // Lire tous les passeports compacts des passes précédentes
  const all_passeports = [];
  for (let i = 1; i <= nb_passes; i++) {
    const path_compact = `${dirs.certification}/${wp_id}_sim_${i}_passeport_compact.json`;
    try {
      all_passeports.push(JSON.parse(fs.readFileSync(path_compact, "utf8")));
    } catch (_) {
      // passe manquante — ignorer
    }
  }

  // Résumé des trajectoires diagnostiquées par passe
  const trajs_par_passe = all_passeports.map(p => ({
    sim:         p.sim_label,
    passe_label: p.passe_label,
    traj:        p.traj_diagn,
    concordant:  p.concordant,
    robustesse:  p.robustesse,
    CCI:         p.CCI,
  }));

  const trajs_uniques = [...new Set(all_passeports.map(p => p.traj_diagn))];
  const nb_concordants = all_passeports.filter(p => p.concordant).length;
  const cci_values = all_passeports.map(p => p.CCI).filter(v => v !== null);
  const cci_moyen  = cci_values.length
    ? cci_values.reduce((a, b) => a + b, 0) / cci_values.length
    : null;

  const robustesse_globale =
    trajs_uniques.length === 1 ? "ROBUSTE" :
    trajs_uniques.length === 2 ? "MÉTASTABLE" : "FRAGILE";

  synthese_passes = {
    wp_id,
    zone,
    nb_passes,
    nb_passes_lues: all_passeports.length,
    generated_at: new Date().toISOString(),
    robustesse_globale,
    trajectoires_uniques: trajs_uniques,
    concordance_taux: `${nb_concordants}/${nb_passes}`,
    cci_moyen: cci_moyen !== null ? Math.round(cci_moyen * 10000) / 10000 : null,
    passes: trajs_par_passe,
  };

  archived.synthese_passes = w(
    `${dirs.certification}/${wp_id}_synthese_passes.json`,
    JSON.stringify(synthese_passes, null, 2)
  );
}

// ── Retour ───────────────────────────────────────────────────────────────────
return {
  json: {
    status:                "ARCHIVE_CERTIFIE",
    pass_count,
    toutes_passes_terminees,
    wp_id,
    sim_label,
    num_passe,
    nb_passes_total:       nb_passes,
    passe_label,
    statut_certification:  cert.statut,
    cci_global:            cert.cci_global,
    robustesse_n1:         cert.robustesse_n1,
    concordance:           cert.concordance,
    verdict_conv_b:        data.verdict_conv_b,
    archived,
    passeport_compact,
    synthese_passes,
    message: synthese_passes
      ? `[WF2 COMPLET] ${wp_id} | ${nb_passes} passes | robustesse=${synthese_passes.robustesse_globale} | CCI_moy=${synthese_passes.cci_moyen}`
      : `[WF2 PASSE ${num_passe}/${nb_passes}] ${wp_id} → ${cert.statut}`,
  }
};

// NŒUD C — Nettoyage /tmp/ entre passes
// Supprime tous les fichiers /tmp/{wp_id}_* de la passe précédente
// Garantit l'isolation entre passes successives sur le même WP
"use strict";
const { execSync } = require("child_process");
const data  = $input.item.json;
const wp_id = data.wp_id || "WP-INCONNU";

let cleaned = [];
let errors  = [];

// Liste des fichiers /tmp/ créés par le pipeline
const patterns = [
  `_runner_config.json`,
  `_result.json`,
  `_n1_sensitivity.json`,
  `_fiche_conv_b.json`,
  `_fiche_conv_e_kappa.json`,
  `_cci_result.json`,
  `_passeport.json`,
  `_n2_optimiste.json`,
  `_n2_pessimiste.json`,
  `_n2_optimiste_result.json`,
  `_n2_pessimiste_result.json`,
  `_revision_counter.txt`
];

for (const suffix of patterns) {
  const path = `/tmp/${wp_id}${suffix}`;
  try {
    execSync(`rm -f ${path}`);
    cleaned.push(path);
  } catch(e) {
    errors.push(`${path}: ${e.message.slice(0,50)}`);
  }
}

return {
  json: {
    ...data,
    cleanup: { cleaned: cleaned.length, errors },
    message: `[CLEANUP] ${wp_id} — ${cleaned.length} fichiers /tmp/ supprimés`
  }
};
